<?php
$pageTitle='Integration Connectors 2.0';
require_once dirname(__DIR__,2) . '/includes/functions.php';
erpGuard('integration_connectors_2');
$pdo=getDB();$apps=$pdo->query('SELECT * FROM '.table('integration_apps').' ORDER BY app_name')->fetchAll();
if($_SERVER['REQUEST_METHOD']==='POST'){
  try{
    $action=(string)($_POST['action']??'install');
    if($action==='install'){$created=installIntegrationConnectorTemplates($pdo);flash('success','Connector templates installed: '.$created);}
    elseif($action==='create_app'){$pdo->prepare('INSERT INTO '.table('integration_connector_templates').' (connector_code,connector_name,provider,category,auth_type,base_url,supported_events,default_scopes,status,description) VALUES (?,?,?,?,?,?,?,?,"available",?) ON DUPLICATE KEY UPDATE connector_name=VALUES(connector_name),provider=VALUES(provider),category=VALUES(category),auth_type=VALUES(auth_type),base_url=VALUES(base_url),supported_events=VALUES(supported_events),default_scopes=VALUES(default_scopes),description=VALUES(description)')->execute([trim((string)$_POST['connector_code']),trim((string)$_POST['connector_name']),trim((string)$_POST['provider']),trim((string)$_POST['category']),trim((string)$_POST['auth_type']),trim((string)$_POST['base_url']),trim((string)$_POST['supported_events']),trim((string)$_POST['default_scopes']),trim((string)$_POST['description'])]);flash('success','Connector template saved.');}
    elseif($action==='connection'){$user=currentUser();$pdo->prepare('INSERT INTO '.table('integration_connections').' (integration_app_id,connection_name,environment,status,credentials_json,settings_json,created_by) VALUES (?,?,?,?,?,?,?)')->execute([(int)$_POST['integration_app_id'],trim((string)$_POST['connection_name']),trim((string)$_POST['environment']),trim((string)$_POST['status']),trim((string)$_POST['credentials_json'])?:'{}',trim((string)$_POST['settings_json'])?:'{}',(int)($user['id']??0)?:null]);flash('success','Integration connection created.');}
    elseif($action==='sync_job'){$number=nextScopedDocumentNumber($pdo,'integration_sync_job','ISJ',operationalScope($pdo));$pdo->prepare('INSERT INTO '.table('integration_sync_jobs').' (integration_connection_id,job_number,sync_type,direction,status,records_total,records_success,records_failed,started_at,finished_at,notes) VALUES (?,?,?,?, "completed", ?, ?, 0, NOW(), NOW(), ?)')->execute([(int)$_POST['connection_id'],$number,trim((string)$_POST['sync_type']),trim((string)$_POST['direction']),max(0,(int)$_POST['records_total']),max(0,(int)$_POST['records_total']),'Manual sync simulation completed.']);flash('success','Sync job simulated.');}
  }catch(Throwable $e){recordSystemError($pdo,$e,['page'=>'integration-connectors-2']);flash('error',$e->getMessage());}
  redirect(ADMIN_URL.'/erp/integration-connectors-2.php');
}
$templates=$pdo->query('SELECT * FROM '.table('integration_connector_templates').' ORDER BY category,connector_name')->fetchAll();
$connections=$pdo->query('SELECT c.*,a.app_name FROM '.table('integration_connections').' c LEFT JOIN '.table('integration_apps').' a ON a.id=c.integration_app_id ORDER BY c.created_at DESC LIMIT 100')->fetchAll();
include dirname(__DIR__).'/header.php';
?>
<div class="d-flex flex-wrap justify-content-between align-items-end gap-3 mb-4"><div><div class="erp-kicker">External Connectors</div><h2 class="h4 mb-1">Integration Connectors 2.0</h2><p class="text-secondary mb-0">Connector templates for WooCommerce, payments, shipping, accounting and marketplaces.</p></div><form method="post"><input type="hidden" name="action" value="install"><button class="btn btn-brand">Install Connectors</button></form></div>
<div class="row g-4"><div class="col-xl-4"><form method="post" class="card-admin p-4 mb-4"><input type="hidden" name="action" value="create_app"><h2 class="h5 mb-3">Connector Template</h2><input class="form-control mb-2" name="connector_code" placeholder="WOOCOMMERCE"><input class="form-control mb-2" name="connector_name" placeholder="WooCommerce"><input class="form-control mb-2" name="provider" placeholder="Provider"><input class="form-control mb-2" name="category" placeholder="E-commerce"><input class="form-control mb-2" name="auth_type" value="api_key"><input class="form-control mb-2" name="base_url" placeholder="https://api.example.com"><input class="form-control mb-2" name="supported_events" placeholder="order.created,product.updated"><input class="form-control mb-2" name="default_scopes" placeholder="read:orders"><textarea class="form-control mb-3" name="description" rows="2"></textarea><button class="btn btn-outline-primary w-100">Save Template</button></form><form method="post" class="card-admin p-4"><input type="hidden" name="action" value="connection"><h2 class="h5 mb-3">Create Connection</h2><select class="form-select mb-2" name="integration_app_id"><?php foreach($apps as $a): ?><option value="<?php echo (int)$a['id']; ?>"><?php echo esc($a['app_name']); ?></option><?php endforeach; ?></select><input class="form-control mb-2" name="connection_name" placeholder="Main Woo Store"><select class="form-select mb-2" name="environment"><option>production</option><option>sandbox</option></select><select class="form-select mb-2" name="status"><option>active</option><option>inactive</option></select><textarea class="form-control mb-2" name="credentials_json" rows="3">{}</textarea><textarea class="form-control mb-3" name="settings_json" rows="3">{}</textarea><button class="btn btn-brand w-100">Create Connection</button></form></div><div class="col-xl-8"><div class="table-wrap table-responsive mb-4"><h2 class="h5 mb-3">Connector Templates</h2><table class="table"><thead><tr><th>Connector</th><th>Provider</th><th>Category</th><th>Auth</th></tr></thead><tbody><?php foreach($templates as $t): ?><tr><td><strong><?php echo esc($t['connector_code']); ?></strong><div class="small text-secondary"><?php echo esc($t['connector_name']); ?></div></td><td><?php echo esc($t['provider']); ?></td><td><?php echo esc($t['category']); ?></td><td><?php echo esc($t['auth_type']); ?></td></tr><?php endforeach; ?></tbody></table></div><div class="table-wrap table-responsive"><h2 class="h5 mb-3">Connections</h2><table class="table"><thead><tr><th>Connection</th><th>App</th><th>Env</th><th>Status</th><th>Simulate</th></tr></thead><tbody><?php foreach($connections as $c): ?><tr><td><strong><?php echo esc($c['connection_name']); ?></strong><div class="small text-secondary"><?php echo esc($c['created_at']); ?></div></td><td><?php echo esc($c['app_name']); ?></td><td><?php echo esc($c['environment']); ?></td><td><span class="badge bg-<?php echo esc(statusTone($c['status'])); ?>"><?php echo esc($c['status']); ?></span></td><td><form method="post" class="d-flex gap-1"><input type="hidden" name="action" value="sync_job"><input type="hidden" name="connection_id" value="<?php echo (int)$c['id']; ?>"><input type="hidden" name="sync_type" value="manual_sync"><input type="hidden" name="direction" value="outbound"><input type="hidden" name="records_total" value="10"><button class="btn btn-sm btn-outline-primary">Sync</button></form></td></tr><?php endforeach; ?></tbody></table></div></div></div>
<?php include dirname(__DIR__).'/footer.php'; ?>